// Cloudflare Worker: Enforce strict cache key normalization

addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});

async function handleRequest(request) {
  const url = new URL(request.url);

  // Define security-critical headers to include in cache key
  const criticalHeaders = [
    'host',
    'x-forwarded-host',
    'x-forwarded-proto',
    'x-forwarded-scheme',
    'origin',
    'referer'
  ];

  // Build normalized cache key
  const cacheKeyComponents = [
    request.method,
    url.pathname,
    url.search.toLowerCase() // Normalize query params
  ];

  // Include critical headers in cache key
  criticalHeaders.forEach(header => {
    const value = request.headers.get(header);
    if (value) {
      cacheKeyComponents.push(`${header}:${value.toLowerCase()}`);
    }
  });

  // Create cache key hash
  const cacheKey = await crypto.subtle.digest(
    'SHA-256',
    new TextEncoder().encode(cacheKeyComponents.join('|'))
  );

  const cacheKeyHex = Array.from(new Uint8Array(cacheKey))
    .map(b => b.toString(16).padStart(2, '0'))
    .join('');

  // Custom Cache Key URL
  const cacheUrl = new URL(request.url);
  cacheUrl.searchParams.set('_cache_key', cacheKeyHex);

  const cacheRequest = new Request(cacheUrl.toString(), request);

  // Check cache with normalized key
  let response = await caches.default.match(cacheRequest);

  if (!response) {
    // Fetch from origin
    response = await fetch(request);

    // Only cache safe responses
    if (response.ok && response.status === 200) {
      // Clone response and add security headers
      const responseToCache = new Response(response.body, response);
      responseToCache.headers.set('X-Cache-Key', cacheKeyHex);
      responseToCache.headers.set('Cache-Control', 'public, max-age=3600, s-maxage=3600');

      // Validate no sensitive data before caching
      const contentType = response.headers.get('content-type') || '';
      const cacheableTypes = ['text/html', 'text/css', 'application/javascript', 'image/'];

      if (cacheableTypes.some(type => contentType.includes(type))) {
        event.waitUntil(caches.default.put(cacheRequest, responseToCache.clone()));
      }
    }
  } else {
    // Add cache hit indicator
    response = new Response(response.body, response);
    response.headers.set('X-Cache-Status', 'HIT');
  }

  return response;
}

// Express.js: Set proper Vary headers and validate forwarded headers

const express = require('express');
const app = express();

// Middleware: Validate and sanitize forwarded headers
app.use((req, res, next) => {
  // Whitelist of allowed hosts
  const allowedHosts = [
    'example.com',
    'www.example.com',
    'api.example.com'
  ];

  // Check X-Forwarded-Host against whitelist
  const forwardedHost = req.headers['x-forwarded-host'];
  if (forwardedHost && !allowedHosts.includes(forwardedHost.toLowerCase())) {
    console.warn(`Blocked suspicious X-Forwarded-Host: ${forwardedHost}`);
    delete req.headers['x-forwarded-host'];
  }

  // Remove dangerous headers that should never come from client
  const dangersHeaders = [
    'x-original-url',
    'x-rewrite-url',
    'x-forwarded-prefix'
  ];

  dangersHeaders.forEach(header => {
    if (req.headers[header]) {
      console.warn(`Removed dangerous header: ${header}`);
      delete req.headers[header];
    }
  });

  // Set Vary header to include security-critical headers
  res.setHeader('Vary', 'Host, Origin, Accept-Encoding');

  next();
});

// Example cacheable endpoint
app.get('/api/profile/:userId', (req, res) => {
  // Ensure Vary includes authentication headers
  res.setHeader('Vary', 'Authorization, Cookie, Host');

  // For authenticated responses, disable caching entirely
  if (req.headers.authorization || req.headers.cookie) {
    res.setHeader('Cache-Control', 'private, no-cache, no-store, must-revalidate');
    res.setHeader('Pragma', 'no-cache');
  } else {
    // Public data can be cached
    res.setHeader('Cache-Control', 'public, max-age=300, s-maxage=600');
  }

  res.json({ userId: req.params.userId, publicData: true });
});

app.listen(3000);

// ============================================
// Nginx Configuration: Header validation at edge
// File: /etc/nginx/conf.d/cache-security.conf
// ============================================

# Strip dangerous headers before proxying to origin
proxy_set_header X-Original-URL "";
proxy_set_header X-Rewrite-URL "";

# Validate X-Forwarded-Host against whitelist
map $http_x_forwarded_host $allowed_host {
    default "";
    "example.com" "example.com";
    "www.example.com" "www.example.com";
    "api.example.com" "api.example.com";
}

# Only pass validated X-Forwarded-Host
proxy_set_header X-Forwarded-Host $allowed_host;

# Cache configuration with proper key
proxy_cache_key "$scheme$proxy_host$request_uri$http_host$http_origin";
proxy_cache_valid 200 10m;
proxy_cache_valid 404 1m;

# Respect Vary header from origin
proxy_cache_vary on;

# Never cache authenticated requests
proxy_no_cache $http_authorization $cookie_session;
proxy_cache_bypass $http_authorization $cookie_session;

location /api/ {
    proxy_pass http://backend;

    # Add cache status to response
    add_header X-Cache-Status $upstream_cache_status;
    add_header X-Cache-Key "$scheme$proxy_host$request_uri$http_host";
}
